$(document).ready(function () {

    var baseUrl = window.location.origin;
    let retrive_data = baseUrl + '/sales_report_ajax';

    let grandTotals = {
        Akki: 0,
        Kai: 0,
        Oil: 0
    };

    var table = $('#view_sales').DataTable({
        processing: true,
        serverSide: true,
        searching: true,
        scrollY: 500,
        scrollX: true,
        scrollCollapse: true,
        destroy: true,
        dom: 'Bfrtip',

        buttons: [

            // ================== ✅ EXCEL ==================
            {
                extend: 'excelHtml5',
                text: 'Export to Excel',
                filename: 'Used_AKO_Report',
                exportOptions: {
                    columns: [0,1,2,3,4,5,6,7]
                },

                action: function (e, dt, button, config) {

                    var self = this;

                    dt.one('preXhr', function (e, s, data) {
                        data.length = -1;
                    });

                    dt.one('draw', function () {

                        $.fn.dataTable.ext.buttons.excelHtml5.action.call(self, e, dt, button, config);

                        dt.one('preXhr', function (e, s, data) {
                            data.length = 10;
                        });

                        setTimeout(function () {
                            dt.ajax.reload();
                        }, 100);
                    });

                    dt.ajax.reload();
                },

                customize: function (xlsx) {

                    var sheet = xlsx.xl.worksheets['sheet1.xml'];
                    var sheetData = $('sheetData', sheet);

                    // ✅ Filters
                    var from_date = $('.from_date').val() || '';
                    var to_date = $('.to_date').val() || '';
                    var financial_year = $('.financial_year option:selected').text() || '';

                    // ✅ Title
                    $('c[r=A1] t', sheet).text('Used AKO Report');

                    var lastRow = $('row', sheet).length + 1;

                    // ✅ Grand Total
                    sheetData.append(`
                        <row r="${lastRow}">
                            <c t="inlineStr" s="2" r="E${lastRow}">
                                <is><t>Grand Total</t></is>
                            </c>
                            <c t="n" s="2" r="F${lastRow}">
                                <v>${grandTotals.Akki}</v>
                            </c>
                            <c t="n" s="2" r="G${lastRow}">
                                <v>${grandTotals.Kai}</v>
                            </c>
                            <c t="n" s="2" r="H${lastRow}">
                                <v>${grandTotals.Oil}</v>
                            </c>
                        </row>
                    `);

                    // ================== ✅ FILTER ROWS ==================
                    var row1 = lastRow + 2;
                    var row2 = lastRow + 3;
                    var row3 = lastRow + 4;

                    // From
                    sheetData.append(`
                        <row r="${row1}">
                            <c t="inlineStr" s="2" r="A${row1}">
                                <is><t>From : ${from_date}</t></is>
                            </c>
                        </row>
                    `);

                    // To
                    sheetData.append(`
                        <row r="${row2}">
                            <c t="inlineStr" s="2" r="A${row2}">
                                <is><t>To : ${to_date}</t></is>
                            </c>
                        </row>
                    `);

                    // Financial Year
                    sheetData.append(`
                        <row r="${row3}">
                            <c t="inlineStr" s="2" r="A${row3}">
                                <is><t>Financial Year : ${financial_year}</t></is>
                            </c>
                        </row>
                    `);
                }
            },

            // ================== ✅ PDF ==================
            {
                extend: 'pdf',
                text: 'Export to PDF',
                filename: 'Used_AKO_Report',
                exportOptions: {
                    columns: [0,1,2,3,4,5,6,7]
                },

                action: function (e, dt, button, config) {

                    var self = this;

                    dt.one('preXhr', function (e, s, data) {
                        data.length = -1;
                    });

                    dt.one('draw', function () {

                        $.fn.dataTable.ext.buttons.pdfHtml5.action.call(self, e, dt, button, config);

                        dt.one('preXhr', function (e, s, data) {
                            data.length = 10;
                        });

                        setTimeout(function () {
                            dt.ajax.reload();
                        }, 100);
                    });

                    dt.ajax.reload();
                },

                customize: function (doc) {

                    var from_date = $('.from_date').val() || '';
                    var to_date = $('.to_date').val() || '';
                    var financial_year = $('.financial_year option:selected').text() || '';

                    // ✅ Title
                    doc.content.splice(0, 0, {
                        text: 'Used AKO Report',
                        fontSize: 14,
                        bold: true,
                        alignment: 'center',
                        margin: [0, 0, 0, 10]
                    });

                    // ✅ Table formatting
                    var table = doc.content.find(item => item.table);
                    if (table) {
                        table.table.widths = ['auto','*','*','*','auto','auto','auto','auto'];
                        table.margin = [20, 0, 30, 0];
                    }

                    // ✅ Grand Total
                    doc.content.push({
                        text: `Grand Total  |  Akki: ${grandTotals.Akki}  |  Kai: ${grandTotals.Kai}  |  Oil: ${grandTotals.Oil}`,
                        alignment: 'center',
                        margin: [0, 10, 0, 5],
                        bold: true
                    });

                    // ✅ FILTER (SEPARATE LINES)
                    doc.content.push({
                        stack: [
                            { text: 'From : ' + from_date },
                            { text: 'To : ' + to_date },
                            { text: 'Financial Year : ' + financial_year }
                        ],
                        margin: [0, 5, 0, 0],
                        bold: true,
                        alignment: 'left'
                    });
                }
            }
        ],

        ajax: {
            url: retrive_data,
            data: function (d) {
                d.from_date = $('.from_date').val();
                d.to_date = $('.to_date').val();
                d.financial_year = $('.financial_year').val();
                d.category = $('.category').val();
                d.subcategory = $('.subcategory').val();
            },
            dataSrc: function (json) {
                if (json.grand_total) {
                    grandTotals.Akki = json.grand_total.Akki;
                    grandTotals.Kai  = json.grand_total.Kai;
                    grandTotals.Oil  = json.grand_total.Oil;
                }
                return json.data;
            }
        },

        columns: [
            {
                data: null,
                render: function (data, type, row, meta) {
                    return meta.row + 1;
                }
            },
            { data: "category_name" },
            { data: "subcategory_name" },
            { data: "detail" },
            { data: "date" },
            { data: "Akki" },
            { data: "Kai" },
            { data: "Oil" },
            {
                title: 'Action',
                render: function (data, type, full) {
                    return `<a href='edit_sales/${full.id}'><i class="ti-pencil-alt"></i></a>`;
                }
            }
        ],

        footerCallback: function () {
            var api = this.api();
            var json = api.ajax.json();

            if (json && json.grand_total) {
                $(api.column(5).footer()).html(json.grand_total.Akki);
                $(api.column(6).footer()).html(json.grand_total.Kai);
                $(api.column(7).footer()).html(json.grand_total.Oil);
            }
        }
    });

    $('.submit_sales_report').click(function () {
         var from_date = $('.from_date').val();
    var to_date = $('.to_date').val();
    var financial_year = $('.financial_year option:selected').text();

    if (!from_date || !to_date || !financial_year) {
        alert("Please select all fields");
        return;
    }

    // ✅ Split financial year
    var yearParts = financial_year.split('-');

    var startYear = yearParts[0];
    var endYear   = yearParts[1];

    // ✅ Financial Year Range
    var fy_start = new Date(startYear + '-04-01');
    var fy_end   = new Date(endYear + '-03-31');

    var from = new Date(from_date);
    var to   = new Date(to_date);

    // ✅ VALIDATION
    if (from < fy_start || to > fy_end) {
        alert("Select date within the financial year");
        return;
    }
      var from_date = $('.from_date').val();
    var to_date = $('.to_date').val();
    var financial_year = $('.financial_year option:selected').text();

    if (!from_date || !to_date || !financial_year) {
        alert("Please select all fields");
        return;
    }

    // ✅ Split financial year
    var yearParts = financial_year.split('-');

    var startYear = yearParts[0];
    var endYear   = yearParts[1];

    // ✅ Financial Year Range
    var fy_start = new Date(startYear + '-04-01');
    var fy_end   = new Date(endYear + '-03-31');

    var from = new Date(from_date);
    var to   = new Date(to_date);

    // ✅ VALIDATION
    if (from < fy_start || to > fy_end) {
        alert("Select date within the financial year");
        return;
    }

    // From Greater the To Date Validation
    if (from > to) {
    alert("From date should not be greater than To date");
    return;
    }
        table.ajax.reload();
    });

});